#include "test_framework.hpp"
#include "mst/mst.hpp"
#include <tuple>
#include <vector>

using namespace cryo;
using namespace cryo_test;

namespace {

Graph make_undirected_graph(size_t n, const std::vector<std::tuple<NodeId, NodeId, double>>& edges) {
    Graph g(GraphType::Undirected);
    for (size_t i = 0; i < n; i++) g.add_node_with_id(i);
    for (const auto& [src, dst, weight] : edges) g.add_edge(src, dst, weight);
    return g;
}

void assert_mst_parity(const Graph& g) {
    auto km = kruskal(g);
    auto pm = prim(g, 0);
    auto bm = boruvka(g);

    assert_near(bm.total_weight, km.total_weight, 1e-9, "boruvka equals kruskal");
    assert_near(bm.total_weight, pm.total_weight, 1e-9, "boruvka equals prim");
    assert_true(is_spanning_tree(g, bm), "boruvka result spans connected graph");
}

} // namespace

CRYO_TEST(MST, BoruvkaConsidersBothEndpointComponents) {
    auto g = make_undirected_graph(4, {
        {0, 1, 1.0},
        {0, 2, 2.0},
        {1, 3, 2.0},
        {2, 3, 100.0},
    });

    auto bm = boruvka(g);
    assert_near(bm.total_weight, 5.0, 1e-9);
    assert_mst_parity(g);
}

CRYO_TEST(MST, BoruvkaMatchesOtherAlgorithmsWithEqualWeights) {
    auto g = make_undirected_graph(5, {
        {0, 1, 1.0},
        {1, 2, 1.0},
        {2, 3, 1.0},
        {3, 4, 1.0},
        {4, 0, 1.0},
        {0, 2, 2.0},
        {1, 3, 2.0},
    });

    auto bm = boruvka(g);
    assert_near(bm.total_weight, 4.0, 1e-9);
    assert_mst_parity(g);
}

CRYO_TEST(MST, BoruvkaMergesMultipleComponentsInOnePhase) {
    auto g = make_undirected_graph(6, {
        {0, 1, 1.0},
        {2, 3, 1.0},
        {4, 5, 1.0},
        {1, 2, 3.0},
        {3, 4, 3.0},
        {0, 5, 10.0},
    });

    auto bm = boruvka(g);
    assert_eq(bm.edges.size(), (size_t)5);
    assert_near(bm.total_weight, 9.0, 1e-9);
    assert_mst_parity(g);
}

CRYO_TEST(MST, BoruvkaSingleNodeGraph) {
    auto g = make_undirected_graph(1, {});
    auto bm = boruvka(g);

    assert_eq(bm.edges.size(), (size_t)0);
    assert_near(bm.total_weight, 0.0, 1e-9);
    assert_false(bm.is_forest);
    assert_true(is_spanning_tree(g, bm));
}

CRYO_TEST(MST, BoruvkaMatchesKruskalForestOnDisconnectedGraph) {
    auto g = make_undirected_graph(6, {
        {0, 1, 1.0},
        {1, 2, 2.0},
        {0, 2, 5.0},
        {3, 4, 3.0},
        {4, 5, 4.0},
        {3, 5, 10.0},
    });

    auto km = kruskal(g);
    auto bm = boruvka(g);

    assert_true(bm.is_forest);
    assert_false(is_spanning_tree(g, bm));
    assert_eq(bm.edges.size(), (size_t)4);
    assert_near(bm.total_weight, 10.0, 1e-9);
    assert_near(bm.total_weight, km.total_weight, 1e-9);
}

CRYO_TEST(MST, BoruvkaParityOnDenseConnectedGraph) {
    auto g = make_undirected_graph(7, {
        {0, 1, 7.0},
        {0, 2, 5.0},
        {0, 3, 3.0},
        {1, 2, 4.0},
        {1, 4, 6.0},
        {2, 3, 2.0},
        {2, 5, 8.0},
        {3, 5, 1.0},
        {4, 5, 2.0},
        {4, 6, 5.0},
        {5, 6, 4.0},
    });

